import{_ as t,o as i,c as a,a2 as s}from"./chunks/framework.CDC-yMab.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md","lastUpdated":1779131907000}'),n={name:"getting-started.md"};function r(o,e,l,p,c,h){return i(),a("div",null,[...e[0]||(e[0]=[s(`<h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><h3 id="quickstart" tabindex="-1">Quickstart <a class="header-anchor" href="#quickstart" aria-label="Permalink to &quot;Quickstart&quot;">​</a></h3><p>Torch can be started with a single command using docker and by providing a configuration file (e.g. .env). See <a href="./configuration.html">Configuration</a> for details on the configuration options.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> torch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [/path/to/.env] -p 8080:8080 ghcr.io/medizininformatik-initiative/torch:v1.0.0-beta.2</span></span></code></pre></div><h3 id="install-prerequisites" tabindex="-1">Install prerequisites <a class="header-anchor" href="#install-prerequisites" aria-label="Permalink to &quot;Install prerequisites&quot;">​</a></h3><p>TORCH interacts with the following components:</p><ul><li>a CQL ready FHIR Server like <a href="https://github.com/samply/blaze" target="_blank" rel="noreferrer">Blaze</a> or <a href="https://github.com/medizininformatik-initiative/flare" target="_blank" rel="noreferrer">FLARE</a> for cohort retrieval</li><li>A FHIR Server / FHIR Search API</li><li>Reverse Proxy (NGINX) (set by configuration)</li></ul><p>The reverse proxy allows for integration into a site&#39;s multi-server infrastructure and provides a means of serving the extracted data. In practice, it acts as a <strong>sidecar container</strong> for TORCH, handling the delivery of generated files.</p><h3 id="feasibility-deploy" tabindex="-1">Feasibility Deploy <a class="header-anchor" href="#feasibility-deploy" aria-label="Permalink to &quot;Feasibility Deploy&quot;">​</a></h3><p>For simplicity torch is integrated in the <a href="https://github.com/medizininformatik-initiative/feasibility-deploy/tree/main/feasibility-triangle" target="_blank" rel="noreferrer">feasibility-triangle</a> of the feasibility-deploy repository, but can also be installed without it.</p><h2 id="transfer-script" tabindex="-1">Transfer Script <a class="header-anchor" href="#transfer-script" aria-label="Permalink to &quot;Transfer Script&quot;">​</a></h2><p>TORCH provides a companion <a href="https://github.com/medizininformatik-initiative/torch/blob/main/scripts/transfer-extraction-to-dup-fhir-server.sh" target="_blank" rel="noreferrer">**transfer script **</a> designed to automate the workflow of submitting a data extraction request, polling the status, and transferring the resulting files to a target FHIR server.</p><p>The transfer script will:</p><ol><li>Take the <strong>CRTDL</strong> and generate a FHIR parameters resource to send to TORCH.</li><li>Execute the $extract-data operation on the TORCH server using the parameters resource as input.</li><li>Poll the TORCH status endpoint until the export is complete.</li><li>Download the resulting patient-oriented FHIR bundles into a temp dir.</li><li>Upload these files to a configured target FHIR server using the <code>blazectl</code> tool.</li><li>Provide progress feedback and error handling at each step.</li></ol><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h2><p>For container images, we use cosign to sign images. This allows users to confirm the image was built by the expected CI pipeline and has not been modified after publication.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cosign verify &quot;ghcr.io/medizininformatik-initiative/torch:v1.0.0&quot; \\</span></span>
<span class="line"><span>--certificate-identity-regexp &quot;https://github.com/medizininformatik-initiative/torch.*&quot; \\</span></span>
<span class="line"><span>--certificate-oidc-issuer &quot;https://token.actions.githubusercontent.com&quot; \\</span></span>
<span class="line"><span>--certificate-github-workflow-ref=&quot;refs/tags/v1.0.0&quot; \\</span></span>
<span class="line"><span>-o text</span></span></code></pre></div><p>The expected output is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Verification for ghcr.io/medizininformatik-initiative/torch:v1.0.0 --</span></span>
<span class="line"><span>The following checks were performed on each of these signatures:</span></span>
<span class="line"><span>- The cosign claims were validated</span></span>
<span class="line"><span>- Existence of the claims in the transparency log was verified offline</span></span>
<span class="line"><span>- The code-signing certificate was verified using trusted certificate authority certificates</span></span></code></pre></div><p>This output ensures that the image was build on the GitHub workflow on the repository <code>medizininformatik-initiative/torch</code> and tag <code>v1.0.0</code>.</p>`,20)])])}const u=t(n,[["render",r]]);export{g as __pageData,u as default};
